#define THREADS 256

inline int mirrorIndex(int d, int sizeD)
{
    if (sizeD <= 1) return 0;
    while (d >= sizeD || d < 0) {
        if (d >= sizeD) d = 2 * sizeD - 2 - d;
        else d = -d;
    }
    return d;
}

inline int loadPixel(__global const int *input, int sx, int sy, int x, int y)
{
    x = mirrorIndex(x, sx);
    y = mirrorIndex(y, sy);
    return input[y * sx + x];
}

inline int rowHigh53(__global const int *input, int sx, int sy, int y, int k)
{
    int c = loadPixel(input, sx, sy, 2 * k + 1, y);
    int p = loadPixel(input, sx, sy, 2 * k + 0, y);
    int n = loadPixel(input, sx, sy, 2 * k + 2, y);
    return c - ((p + n) / 2);
}

inline int rowLow53(__global const int *input, int sx, int sy, int y, int k, int hx)
{
    int s = loadPixel(input, sx, sy, 2 * k, y);
    if (hx <= 0) return s;

    int km1 = mirrorIndex(k - 1, hx);
    int k0  = mirrorIndex(k, hx);
    int dm1 = rowHigh53(input, sx, sy, y, km1);
    int d0  = rowHigh53(input, sx, sy, y, k0);
    return s + ((dm1 + d0 + 2) / 4);
}

inline int colHighLowX53(__global const int *input, int sx, int sy, int j, int cx, int hx)
{
    int c = rowLow53(input, sx, sy, 2 * j + 1, cx, hx);
    int p = rowLow53(input, sx, sy, 2 * j + 0, cx, hx);
    int n = rowLow53(input, sx, sy, 2 * j + 2, cx, hx);
    return c - ((p + n) / 2);
}

inline int colLowLowX53(__global const int *input, int sx, int sy, int i, int cx, int hx, int hy)
{
    int a = rowLow53(input, sx, sy, 2 * i, cx, hx);
    if (hy <= 0) return a;

    int im1 = mirrorIndex(i - 1, hy);
    int i0  = mirrorIndex(i, hy);
    int hm1 = colHighLowX53(input, sx, sy, im1, cx, hx);
    int h0  = colHighLowX53(input, sx, sy, i0, cx, hx);
    return a + ((hm1 + h0 + 2) / 4);
}

inline int colHighHighX53(__global const int *input, int sx, int sy, int j, int cx)
{
    int c = rowHigh53(input, sx, sy, 2 * j + 1, cx);
    int p = rowHigh53(input, sx, sy, 2 * j + 0, cx);
    int n = rowHigh53(input, sx, sy, 2 * j + 2, cx);
    return c - ((p + n) / 2);
}

inline int colLowHighX53(__global const int *input, int sx, int sy, int i, int cx, int hy)
{
    int a = rowHigh53(input, sx, sy, 2 * i, cx);
    if (hy <= 0) return a;

    int im1 = mirrorIndex(i - 1, hy);
    int i0  = mirrorIndex(i, hy);
    int hm1 = colHighHighX53(input, sx, sy, im1, cx);
    int h0  = colHighHighX53(input, sx, sy, i0, cx);
    return a + ((hm1 + h0 + 2) / 4);
}

__kernel void c_CopySrcToComponents(__global int *d_r, __global int *d_g, __global int *d_b,
                                    __global const uchar *d_src, int pixels)
{
    int gid = (int)get_global_id(0);
    if (gid < pixels) {
        int base = gid * 3;
        d_r[gid] = (int)d_src[base + 0] - 128;
        d_g[gid] = (int)d_src[base + 1] - 128;
        d_b[gid] = (int)d_src[base + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c, __global const uchar *d_src, int pixels)
{
    int gid = (int)get_global_id(0);
    if (gid < pixels) {
        d_c[gid] = (int)d_src[gid] - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input, __global int *output,
                              int sizeX, int sizeY, int winSteps,
                              int WIN_SX, int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    int xg = (int)get_global_id(0);
    int gy = (int)get_num_groups(1);
    int by = (int)get_group_id(1);

    int lx = (sizeX + 1) >> 1;
    int hx = sizeX - lx;
    int ly = (sizeY + 1) >> 1;
    int hy = sizeY - ly;

    int offLL = 0;
    int offHL = lx * ly;
    int offLH = offHL + hx * ly;
    int offHH = offLH + lx * hy;

    if (xg < lx) {
        for (int i = by; i < ly; i += gy) {
            int v = colLowLowX53(input, sizeX, sizeY, i, xg, hx, hy);
            output[offLL + i * lx + xg] = v;
        }
        for (int j = by; j < hy; j += gy) {
            int v = colHighLowX53(input, sizeX, sizeY, j, xg, hx);
            output[offLH + j * lx + xg] = v;
        }
    }

    if (xg < hx) {
        for (int i = by; i < ly; i += gy) {
            int v = colLowHighX53(input, sizeX, sizeY, i, xg, hy);
            output[offHL + i * hx + xg] = v;
        }
        for (int j = by; j < hy; j += gy) {
            int v = colHighHighX53(input, sizeX, sizeY, j, xg);
            output[offHH + j * hx + xg] = v;
        }
    }
}
